onClick:
{{ 
  (async () => {
    // 1. Validamos que el nombre no esté vacío
    if (!Input_Nombre.text) {
      return showAlert('Por favor, introduce el nombre del técnico', 'warning');
    }

    try {
      // 2. Ejecutamos la creación en la DB
      await addPersonal.run();

      // 3. Feedback visual de éxito
      showAlert('Técnico ' + Input_Nombre.text + ' creado con éxito', 'success');

      // 4. Limpieza y refresco
      closeModal('ModalAdd');
      await getPersonal.run(); // Para que aparezca en la tabla de colorines
      resetWidget("Modal_Nuevo_Personal", true);

    } catch (error) {
      showAlert('Error al crear personal: ' + error.message, 'error');
    }
  })() 
}}
